import { useState, forwardRef } from 'react';
import { motion } from 'framer-motion';

const FloatingLabelInput = forwardRef(function FloatingLabelInput(
    { label, error, type = 'text', className = '', hint, ...props },
    ref
) {
    const [focused, setFocused] = useState(false);
    const hasValue = !!props.value;

    return (
        <div style={{ display: 'flex', flexDirection: 'column', gap: '6px' }}>
            {label && (
                <label
                    style={{
                        fontSize: '0.75rem',
                        fontWeight: 600,
                        color: error ? 'var(--error)' : focused ? 'var(--accent-light)' : 'var(--text-secondary)',
                        letterSpacing: '0.01em',
                        transition: 'color 0.15s',
                    }}
                >
                    {label}
                </label>
            )}
            <motion.input
                ref={ref}
                type={type}
                animate={error ? { x: [0, -6, 6, -4, 4, 0] } : { x: 0 }}
                transition={{ duration: 0.35 }}
                onFocus={() => setFocused(true)}
                onBlur={() => setFocused(false)}
                className={`input-field ${error ? 'has-error' : ''} ${className}`}
                {...props}
            />
            {error && (
                <motion.p
                    initial={{ opacity: 0, y: -4 }}
                    animate={{ opacity: 1, y: 0 }}
                    style={{ fontSize: '0.75rem', color: 'var(--error)', display: 'flex', alignItems: 'center', gap: '4px' }}
                >
                    <svg width="12" height="12" viewBox="0 0 24 24" fill="currentColor"><path d="M12 2C6.477 2 2 6.477 2 12s4.477 10 10 10 10-4.477 10-10S17.523 2 12 2zm1 15h-2v-2h2v2zm0-4h-2V7h2v6z" /></svg>
                    {error}
                </motion.p>
            )}
            {hint && !error && (
                <p style={{ fontSize: '0.75rem', color: 'var(--text-muted)' }}>{hint}</p>
            )}
        </div>
    );
});

export default FloatingLabelInput;

import { motion } from 'framer-motion';

const features = [
    {
        icon: (
            <svg width="18" height="18" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="1.75">
                <path strokeLinecap="round" strokeLinejoin="round" d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2" />
            </svg>
        ),
        title: 'Smart Queue Management',
        desc: 'Real-time token system eliminates waiting room chaos.',
    },
    {
        icon: (
            <svg width="18" height="18" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="1.75">
                <path strokeLinecap="round" strokeLinejoin="round" d="M9 12l2 2 4-4m5.618-4.016A11.955 11.955 0 0112 2.944a11.955 11.955 0 01-8.618 3.04A12.02 12.02 0 003 9c0 5.591 3.824 10.29 9 11.622 5.176-1.332 9-6.03 9-11.622 0-1.042-.133-2.052-.382-3.016z" />
            </svg>
        ),
        title: 'Prescription Workflow',
        desc: 'Seamless doctor-to-chemist digital prescription flow.',
    },
    {
        icon: (
            <svg width="18" height="18" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="1.75">
                <path strokeLinecap="round" strokeLinejoin="round" d="M13 10V3L4 14h7v7l9-11h-7z" />
            </svg>
        ),
        title: 'Live Status Tracking',
        desc: 'Patients track their queue position in real time.',
    },
];

const stats = [
    { value: '10k+', label: 'Patient Records' },
    { value: '99.9%', label: 'Uptime SLA' },
    { value: '< 1s', label: 'Load Time' },
];

const containerVariants = {
    hidden: {},
    visible: { transition: { staggerChildren: 0.1 } },
};
const itemVariants = {
    hidden: { opacity: 0, x: -16 },
    visible: { opacity: 1, x: 0, transition: { duration: 0.4, ease: 'easeOut' } },
};

export default function HeroPanel() {
    return (
        <div style={{
            height: '100%',
            display: 'flex',
            flexDirection: 'column',
            justifyContent: 'space-between',
            padding: '40px',
        }}>
            {/* Top: Logo + Tagline */}
            <div>
                {/* Logo */}
                <motion.div
                    initial={{ opacity: 0, y: -10 }}
                    animate={{ opacity: 1, y: 0 }}
                    transition={{ duration: 0.4 }}
                    style={{ display: 'flex', alignItems: 'center', gap: '10px', marginBottom: '40px' }}
                >
                    <div className="logo-mark">
                        <svg width="20" height="20" fill="white" viewBox="0 0 24 24">
                            <path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm1 15h-2v-6H9l3-7 3 7h-2v6z" />
                        </svg>
                    </div>
                    <span style={{ fontSize: '1.125rem', fontWeight: 800, letterSpacing: '-0.03em', color: 'var(--text-primary)' }}>
                        Qure
                    </span>
                    <span style={{
                        marginLeft: '4px',
                        padding: '2px 8px',
                        background: 'var(--accent-bg)',
                        border: '1px solid rgba(88,101,242,0.25)',
                        borderRadius: '20px',
                        fontSize: '0.6875rem',
                        fontWeight: 600,
                        color: 'var(--accent-light)',
                        letterSpacing: '0.05em',
                    }}>
                        BETA
                    </span>
                </motion.div>

                {/* Headline */}
                <motion.div
                    initial={{ opacity: 0, y: 12 }}
                    animate={{ opacity: 1, y: 0 }}
                    transition={{ duration: 0.5, delay: 0.1 }}
                >
                    <h1 className="t-display" style={{ marginBottom: '12px' }}>
                        Healthcare,
                        <br />
                        <span className="gradient-text">Re-engineered.</span>
                    </h1>
                    <p className="t-body" style={{ maxWidth: '320px', lineHeight: 1.7 }}>
                        Qure is a digital-first platform that connects hospitals,
                        doctors, and patients ΓÇö making healthcare smarter for everyone.
                    </p>
                </motion.div>

                {/* Features */}
                <motion.div
                    variants={containerVariants}
                    initial="hidden"
                    animate="visible"
                    style={{ marginTop: '36px', display: 'flex', flexDirection: 'column', gap: '16px' }}
                >
                    {features.map((f) => (
                        <motion.div
                            key={f.title}
                            variants={itemVariants}
                            style={{
                                display: 'flex',
                                gap: '14px',
                                alignItems: 'flex-start',
                            }}
                        >
                            <div style={{
                                width: '36px',
                                height: '36px',
                                borderRadius: '10px',
                                background: 'var(--accent-bg)',
                                border: '1px solid rgba(88,101,242,0.2)',
                                display: 'flex',
                                alignItems: 'center',
                                justifyContent: 'center',
                                color: 'var(--accent-light)',
                                flexShrink: 0,
                            }}>
                                {f.icon}
                            </div>
                            <div>
                                <p style={{ fontSize: '0.875rem', fontWeight: 600, color: 'var(--text-primary)', marginBottom: '2px' }}>
                                    {f.title}
                                </p>
                                <p style={{ fontSize: '0.8125rem', color: 'var(--text-secondary)', lineHeight: 1.5 }}>
                                    {f.desc}
                                </p>
                            </div>
                        </motion.div>
                    ))}
                </motion.div>
            </div>

            {/* Bottom: Stats */}
            <motion.div
                initial={{ opacity: 0, y: 16 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ duration: 0.5, delay: 0.5 }}
            >
                <div style={{ height: '1px', background: 'var(--border)', marginBottom: '24px' }} />
                <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: '12px' }}>
                    {stats.map(s => (
                        <div key={s.label} className="stat-card">
                            <p style={{ fontSize: '1.25rem', fontWeight: 800, letterSpacing: '-0.03em', color: 'var(--text-primary)', marginBottom: '2px' }}>
                                {s.value}
                            </p>
                            <p style={{ fontSize: '0.6875rem', color: 'var(--text-muted)', fontWeight: 500 }}>{s.label}</p>
                        </div>
                    ))}
                </div>
                <p style={{ marginTop: '20px', fontSize: '0.75rem', color: 'var(--text-muted)' }}>
                    Trusted by healthcare providers across India ┬╖ HIPAA-aligned
                </p>
            </motion.div>
        </div>
    );
}

import { motion } from 'framer-motion';

const OPTIONS = [
    {
        value: 'hospital',
        label: 'Healthcare Provider',
        icon: (
            <svg width="15" height="15" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="2">
                <path strokeLinecap="round" strokeLinejoin="round" d="M19 21V5a2 2 0 00-2-2H7a2 2 0 00-2 2v16m14 0H5m7-11v6m-3-3h6" />
            </svg>
        ),
    },
    {
        value: 'patient',
        label: 'Patient',
        icon: (
            <svg width="15" height="15" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="2">
                <path strokeLinecap="round" strokeLinejoin="round" d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" />
            </svg>
        ),
    },
];

export default function IdentityToggle({ value, onChange }) {
    return (
        <div className="seg-control">
            {OPTIONS.map((opt) => {
                const active = value === opt.value;
                return (
                    <motion.button
                        key={opt.value}
                        type="button"
                        onClick={() => onChange(opt.value)}
                        whileTap={{ scale: 0.97 }}
                        className={`seg-btn ${active ? 'active' : ''}`}
                    >
                        <span style={{ color: active ? 'var(--accent)' : 'var(--text-muted)', display: 'flex' }}>
                            {opt.icon}
                        </span>
                        {opt.label}
                    </motion.button>
                );
            })}
        </div>
    );
}

import { forwardRef, useState } from 'react';
import { motion } from 'framer-motion';

const MaskedPhoneInput = forwardRef(function MaskedPhoneInput(
    { label, error, optional = false, dim = false, onChange, onBlur, name, value, ...rest },
    ref
) {
    const [focused, setFocused] = useState(false);

    /* Format digits ΓåÆ XXX-XXX-XXXX for display */
    const formatDisplay = (raw) => {
        const d = (raw || '').replace(/\D/g, '').slice(0, 10);
        if (d.length > 6) return `${d.slice(0, 3)}-${d.slice(3, 6)}-${d.slice(6)}`;
        if (d.length > 3) return `${d.slice(0, 3)}-${d.slice(3)}`;
        return d;
    };

    const handleChange = (e) => {
        /* Strip to raw digits, store raw in RHF */
        const raw = e.target.value.replace(/\D/g, '').slice(0, 10);
        e.target.value = raw;
        onChange?.(e);
    };

    return (
        <div style={{ display: 'flex', flexDirection: 'column', gap: '6px', opacity: dim ? 0.45 : 1, transition: 'opacity 0.2s' }}>
            {label && (
                <label style={{
                    fontSize: '0.75rem', fontWeight: 600,
                    color: error ? 'var(--error)' : focused ? 'var(--accent-light)' : 'var(--text-secondary)',
                    letterSpacing: '0.01em', transition: 'color 0.15s',
                }}>
                    {label}
                    {optional && <span style={{ fontWeight: 400, color: 'var(--text-muted)', marginLeft: '4px' }}>(optional)</span>}
                </label>
            )}
            <motion.div
                animate={error ? { x: [0, -6, 6, -4, 4, 0] } : { x: 0 }}
                transition={{ duration: 0.35 }}
                style={{
                    display: 'flex',
                    alignItems: 'center',
                    borderRadius: '10px',
                    border: `1px solid ${error ? 'var(--error)' : focused ? 'var(--accent)' : 'var(--border)'}`,
                    background: 'var(--bg-input)',
                    boxShadow: focused ? (error ? '0 0 0 3px rgba(244,63,94,0.12)' : '0 0 0 3px var(--accent-glow)') : 'none',
                    overflow: 'hidden',
                    transition: 'border-color 0.15s, box-shadow 0.15s',
                }}
            >
                <span style={{
                    padding: '0 12px',
                    fontSize: '0.8125rem',
                    fontWeight: 600,
                    color: 'var(--accent-light)',
                    borderRight: '1px solid var(--border)',
                    alignSelf: 'stretch',
                    display: 'flex',
                    alignItems: 'center',
                    flexShrink: 0,
                }}>
                    +91
                </span>
                <input
                    ref={ref}
                    name={name}
                    type="tel"
                    placeholder="XXX-XXX-XXXX"
                    value={formatDisplay(value)}
                    onFocus={() => setFocused(true)}
                    onBlur={(e) => { setFocused(false); onBlur?.(e); }}
                    onChange={handleChange}
                    style={{
                        flex: 1,
                        padding: '0.75rem',
                        background: 'transparent',
                        border: 'none',
                        outline: 'none',
                        fontSize: '0.875rem',
                        color: 'var(--text-primary)',
                        fontFamily: 'Inter, sans-serif',
                    }}
                />
            </motion.div>
            {error && (
                <p style={{ fontSize: '0.75rem', color: 'var(--error)', display: 'flex', alignItems: 'center', gap: '4px' }}>
                    <svg width="12" height="12" viewBox="0 0 24 24" fill="currentColor"><path d="M12 2C6.477 2 2 6.477 2 12s4.477 10 10 10 10-4.477 10-10S17.523 2 12 2zm1 15h-2v-2h2v2zm0-4h-2V7h2v6z" /></svg>
                    {error}
                </p>
            )}
        </div>
    );
});

export default MaskedPhoneInput;

import { motion } from 'framer-motion';

const Loader = () => (
    <svg className="spin" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5">
        <path d="M12 2v4M12 18v4M4.93 4.93l2.83 2.83M16.24 16.24l2.83 2.83M2 12h4M18 12h4M4.93 19.07l2.83-2.83M16.24 7.76l2.83-2.83" />
    </svg>
);
const CheckIcon = () => (
    <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5">
        <path strokeLinecap="round" strokeLinejoin="round" d="M5 13l4 4L19 7" />
    </svg>
);

export default function PulseButton({ children, loading, success, error: hasError, disabled, style = {}, ...props }) {
    let bg = 'var(--accent)';
    let hoverBg = '#4f56e8';
    let color = 'white';
    let shadow = '';

    if (success) { bg = 'var(--success)'; hoverBg = '#0da071'; }
    if (hasError) { bg = 'rgba(244,63,94,0.15)'; color = 'var(--error)'; }
    if (disabled || loading) { bg = 'var(--bg-elevated)'; color = 'var(--text-muted)'; }

    return (
        <motion.button
            whileTap={!disabled && !loading ? { scale: 0.98 } : {}}
            className={`btn-primary ${loading ? 'pulse-ring' : ''}`}
            disabled={loading || disabled}
            style={{ background: bg, color, ...style }}
            {...props}
        >
            {loading && <Loader />}
            {success && <CheckIcon />}
            {loading ? 'Processing...' : success ? 'Done!' : children}
        </motion.button>
    );
}

import { useState, useRef, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';

const ChevronDown = () => (
    <svg width="14" height="14" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="2.5">
        <path strokeLinecap="round" strokeLinejoin="round" d="M19 9l-7 7-7-7" />
    </svg>
);
const SearchIcon = () => (
    <svg width="13" height="13" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="2.5">
        <circle cx="11" cy="11" r="8" /><path strokeLinecap="round" strokeLinejoin="round" d="M21 21l-4.35-4.35" />
    </svg>
);
const CheckIcon = () => (
    <svg width="13" height="13" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="2.5">
        <path strokeLinecap="round" strokeLinejoin="round" d="M5 13l4 4L19 7" />
    </svg>
);

export default function SearchableSelect({ label, options = [], value, onChange, error, placeholder = 'Select...' }) {
    const [open, setOpen] = useState(false);
    const [query, setQuery] = useState('');
    const ref = useRef(null);

    const filtered = options.filter(o => o.label.toLowerCase().includes(query.toLowerCase()));
    const selected = options.find(o => o.value === value);

    useEffect(() => {
        const fn = (e) => { if (!ref.current?.contains(e.target)) setOpen(false); };
        document.addEventListener('mousedown', fn);
        return () => document.removeEventListener('mousedown', fn);
    }, []);

    return (
        <div ref={ref} style={{ display: 'flex', flexDirection: 'column', gap: '6px' }}>
            {label && (
                <label style={{ fontSize: '0.75rem', fontWeight: 600, color: error ? 'var(--error)' : 'var(--text-secondary)', letterSpacing: '0.01em' }}>
                    {label}
                </label>
            )}
            <button
                type="button"
                onClick={() => setOpen(p => !p)}
                className={`input-field ${error ? 'has-error' : ''}`}
                style={{
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'space-between',
                    color: selected ? 'var(--text-primary)' : 'var(--text-muted)',
                    textAlign: 'left',
                }}
            >
                <span>{selected ? selected.label : placeholder}</span>
                <motion.span
                    animate={{ rotate: open ? 180 : 0 }}
                    transition={{ duration: 0.2 }}
                    style={{ color: 'var(--text-muted)', flexShrink: 0 }}
                >
                    <ChevronDown />
                </motion.span>
            </button>

            <AnimatePresence>
                {open && (
                    <motion.div
                        initial={{ opacity: 0, y: -6, scale: 0.98 }}
                        animate={{ opacity: 1, y: 0, scale: 1 }}
                        exit={{ opacity: 0, y: -6, scale: 0.98 }}
                        transition={{ duration: 0.15, ease: 'easeOut' }}
                        style={{
                            position: 'absolute',
                            zIndex: 100,
                            width: '100%',
                            marginTop: '64px',
                            background: 'var(--bg-elevated)',
                            border: '1px solid var(--border)',
                            borderRadius: '12px',
                            overflow: 'hidden',
                            boxShadow: '0 8px 32px rgba(0,0,0,0.5), 0 0 0 1px rgba(88,101,242,0.1)',
                        }}
                    >
                        <div style={{
                            display: 'flex',
                            alignItems: 'center',
                            gap: '8px',
                            padding: '10px 12px',
                            borderBottom: '1px solid var(--border)',
                        }}>
                            <span style={{ color: 'var(--text-muted)', flexShrink: 0 }}><SearchIcon /></span>
                            <input
                                autoFocus
                                value={query}
                                onChange={e => setQuery(e.target.value)}
                                placeholder="Search..."
                                style={{
                                    flex: 1,
                                    background: 'transparent',
                                    border: 'none',
                                    outline: 'none',
                                    fontSize: '0.8125rem',
                                    color: 'var(--text-primary)',
                                    fontFamily: 'Inter, sans-serif',
                                }}
                            />
                        </div>
                        <div style={{ maxHeight: '200px', overflowY: 'auto' }}>
                            {filtered.length === 0 ? (
                                <p style={{ textAlign: 'center', fontSize: '0.8125rem', color: 'var(--text-muted)', padding: '16px' }}>No results</p>
                            ) : filtered.map(opt => (
                                <button
                                    key={opt.value}
                                    type="button"
                                    onClick={() => { onChange(opt.value); setOpen(false); setQuery(''); }}
                                    style={{
                                        width: '100%',
                                        textAlign: 'left',
                                        padding: '9px 14px',
                                        display: 'flex',
                                        alignItems: 'center',
                                        justifyContent: 'space-between',
                                        fontSize: '0.8125rem',
                                        fontFamily: 'Inter, sans-serif',
                                        background: value === opt.value ? 'var(--accent-bg)' : 'transparent',
                                        color: value === opt.value ? 'var(--accent-light)' : 'var(--text-secondary)',
                                        border: 'none',
                                        cursor: 'pointer',
                                        transition: 'background 0.1s',
                                    }}
                                    onMouseEnter={e => { if (value !== opt.value) e.target.style.background = 'rgba(255,255,255,0.04)'; }}
                                    onMouseLeave={e => { if (value !== opt.value) e.target.style.background = 'transparent'; }}
                                >
                                    {opt.label}
                                    {value === opt.value && <CheckIcon />}
                                </button>
                            ))}
                        </div>
                    </motion.div>
                )}
            </AnimatePresence>

            {error && (
                <p style={{ fontSize: '0.75rem', color: 'var(--error)', display: 'flex', alignItems: 'center', gap: '4px' }}>
                    <svg width="12" height="12" viewBox="0 0 24 24" fill="currentColor"><path d="M12 2C6.477 2 2 6.477 2 12s4.477 10 10 10 10-4.477 10-10S17.523 2 12 2zm1 15h-2v-2h2v2zm0-4h-2V7h2v6z" /></svg>
                    {error}
                </p>
            )}
        </div>
    );
}

import { motion } from 'framer-motion';

export default function StepIndicator({ steps, currentStep }) {
    return (
        <div style={{ display: 'flex', alignItems: 'flex-start', gap: '0' }}>
            {steps.map((step, idx) => {
                const done = idx < currentStep;
                const active = idx === currentStep;
                return (
                    <div key={idx} style={{ display: 'flex', alignItems: 'center', flex: idx < steps.length - 1 ? 1 : 'none' }}>
                        <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '6px' }}>
                            <motion.div
                                initial={false}
                                animate={{
                                    background: done ? 'var(--accent)' : active ? 'var(--accent)' : 'var(--bg-input)',
                                    borderColor: done || active ? 'var(--accent)' : 'var(--border)',
                                    scale: active ? 1.1 : 1,
                                }}
                                transition={{ duration: 0.2 }}
                                style={{
                                    width: '28px',
                                    height: '28px',
                                    borderRadius: '50%',
                                    border: '1.5px solid',
                                    display: 'flex',
                                    alignItems: 'center',
                                    justifyContent: 'center',
                                    flexShrink: 0,
                                    zIndex: 1,
                                }}
                            >
                                {done ? (
                                    <svg width="12" height="12" fill="none" viewBox="0 0 24 24" stroke="white" strokeWidth="3">
                                        <path strokeLinecap="round" strokeLinejoin="round" d="M5 13l4 4L19 7" />
                                    </svg>
                                ) : (
                                    <span style={{
                                        fontSize: '0.6875rem',
                                        fontWeight: 700,
                                        color: active ? 'white' : 'var(--text-muted)',
                                    }}>{idx + 1}</span>
                                )}
                            </motion.div>
                            <span style={{
                                fontSize: '0.6875rem',
                                fontWeight: active ? 600 : 400,
                                color: active ? 'var(--accent-light)' : done ? 'var(--text-secondary)' : 'var(--text-muted)',
                                whiteSpace: 'nowrap',
                            }}>
                                {step}
                            </span>
                        </div>

                        {idx < steps.length - 1 && (
                            <div style={{ flex: 1, height: '1.5px', background: 'var(--border)', margin: '0 8px', marginBottom: '20px', position: 'relative', overflow: 'hidden' }}>
                                <motion.div
                                    initial={false}
                                    animate={{ scaleX: done ? 1 : 0 }}
                                    transition={{ duration: 0.35, ease: 'easeInOut' }}
                                    style={{ position: 'absolute', inset: 0, background: 'var(--accent)', transformOrigin: 'left' }}
                                />
                            </div>
                        )}
                    </div>
                );
            })}
        </div>
    );
}

import { useState, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';

const XIcon = () => (
    <svg width="10" height="10" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="3">
        <path strokeLinecap="round" strokeLinejoin="round" d="M6 18L18 6M6 6l12 12" />
    </svg>
);

export default function TagChipInput({ label, value = [], onChange, placeholder = 'Type and press Enter', error }) {
    const [input, setInput] = useState('');
    const inputRef = useRef(null);

    const addTag = () => {
        const t = input.trim();
        if (t && !value.includes(t)) onChange([...value, t]);
        setInput('');
    };

    const removeTag = (tag) => onChange(value.filter(t => t !== tag));

    const handleKeyDown = (e) => {
        if (e.key === 'Enter') { e.preventDefault(); addTag(); }
        if (e.key === 'Backspace' && !input && value.length > 0) removeTag(value[value.length - 1]);
    };

    return (
        <div style={{ display: 'flex', flexDirection: 'column', gap: '6px' }}>
            {label && (
                <label style={{ fontSize: '0.75rem', fontWeight: 600, color: error ? 'var(--error)' : 'var(--text-secondary)', letterSpacing: '0.01em' }}>
                    {label}
                </label>
            )}
            <div
                onClick={() => inputRef.current?.focus()}
                className={`input-field ${error ? 'has-error' : ''}`}
                style={{
                    minHeight: '48px',
                    display: 'flex',
                    flexWrap: 'wrap',
                    alignItems: 'center',
                    gap: '6px',
                    cursor: 'text',
                    padding: '8px 12px',
                    height: 'auto',
                }}
            >
                <AnimatePresence>
                    {value.map(tag => (
                        <motion.span
                            key={tag}
                            initial={{ opacity: 0, scale: 0.8 }}
                            animate={{ opacity: 1, scale: 1 }}
                            exit={{ opacity: 0, scale: 0.8 }}
                            transition={{ duration: 0.15 }}
                            className="chip"
                        >
                            {tag}
                            <button
                                type="button"
                                onClick={e => { e.stopPropagation(); removeTag(tag); }}
                                style={{ background: 'none', border: 'none', cursor: 'pointer', color: 'inherit', display: 'flex', alignItems: 'center', padding: '1px' }}
                            >
                                <XIcon />
                            </button>
                        </motion.span>
                    ))}
                </AnimatePresence>
                <input
                    ref={inputRef}
                    value={input}
                    onChange={e => setInput(e.target.value)}
                    onKeyDown={handleKeyDown}
                    placeholder={value.length === 0 ? placeholder : ''}
                    style={{
                        flex: 1,
                        minWidth: '100px',
                        background: 'transparent',
                        border: 'none',
                        outline: 'none',
                        fontSize: '0.875rem',
                        color: 'var(--text-primary)',
                        fontFamily: 'Inter, sans-serif',
                    }}
                />
            </div>
            <p style={{ fontSize: '0.75rem', color: 'var(--text-muted)' }}>Press Enter to add ┬╖ Backspace to remove last</p>
        </div>
    );
}

