import { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { motion } from 'framer-motion';
import FloatingLabelInput from '../components/FloatingLabelInput';
import PulseButton from '../components/PulseButton';

export default function LoginPage() {
    const navigate = useNavigate();
    const [role, setRole] = useState('hospital');
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState('');

    const handleSubmit = async (e) => {
        e.preventDefault();
        if (!email || !password) { setError('Please fill in all fields.'); return; }
        setLoading(true);
        setError('');
        try {
            // TODO: hook up to your /auth/login endpoint
            await new Promise(r => setTimeout(r, 1200)); // simulate API
            navigate('/');
        } catch (err) {
            setError(err.message || 'Invalid credentials. Please try again.');
        } finally {
            setLoading(false);
        }
    };

    return (
        <div style={{
            position: 'relative',
            zIndex: 10,
            minHeight: '100vh',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            padding: '24px',
        }}>
            <motion.div
                initial={{ opacity: 0, y: 16 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ duration: 0.4, ease: 'easeOut' }}
                style={{ width: '100%', maxWidth: '440px' }}
            >
                {/* Logo */}
                <div style={{ display: 'flex', alignItems: 'center', gap: '10px', marginBottom: '32px', justifyContent: 'center' }}>
                    <div className="logo-mark">
                        <svg width="20" height="20" fill="white" viewBox="0 0 24 24">
                            <path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm1 15h-2v-6H9l3-7 3 7h-2v6z" />
                        </svg>
                    </div>
                    <span style={{ fontSize: '1.25rem', fontWeight: 800, letterSpacing: '-0.03em', color: 'var(--text-primary)' }}>
                        Qure
                    </span>
                </div>

                <div className="card" style={{ padding: '32px' }}>
                    {/* Header */}
                    <div style={{ marginBottom: '24px' }}>
                        <h1 style={{ fontSize: '1.375rem', fontWeight: 800, letterSpacing: '-0.03em', color: 'var(--text-primary)', marginBottom: '4px' }}>
                            Sign in to Qure
                        </h1>
                        <p style={{ fontSize: '0.875rem', color: 'var(--text-secondary)' }}>
                            Welcome back ΓÇö let's get you in.
                        </p>
                    </div>

                    {/* Role selector */}
                    <div style={{ marginBottom: '20px' }}>
                        <div className="seg-control">
                            {[
                                {
                                    value: 'hospital', label: 'Healthcare Provider', icon: (
                                        <svg width="14" height="14" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="2">
                                            <path strokeLinecap="round" strokeLinejoin="round" d="M19 21V5a2 2 0 00-2-2H7a2 2 0 00-2 2v16m14 0H5m7-11v6m-3-3h6" />
                                        </svg>
                                    )
                                },
                                {
                                    value: 'patient', label: 'Patient', icon: (
                                        <svg width="14" height="14" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="2">
                                            <path strokeLinecap="round" strokeLinejoin="round" d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" />
                                        </svg>
                                    )
                                },
                            ].map(opt => (
                                <button
                                    key={opt.value}
                                    type="button"
                                    onClick={() => setRole(opt.value)}
                                    className={`seg-btn ${role === opt.value ? 'active' : ''}`}
                                >
                                    <span style={{ color: role === opt.value ? 'var(--accent)' : 'var(--text-muted)' }}>{opt.icon}</span>
                                    {opt.label}
                                </button>
                            ))}
                        </div>
                    </div>

                    {/* Form */}
                    <form onSubmit={handleSubmit} style={{ display: 'flex', flexDirection: 'column', gap: '14px' }}>
                        <FloatingLabelInput
                            label="Email Address"
                            type="email"
                            placeholder="you@example.com"
                            value={email}
                            onChange={e => { setEmail(e.target.value); setError(''); }}
                        />
                        <div>
                            <FloatingLabelInput
                                label="Password"
                                type="password"
                                placeholder="Your password"
                                value={password}
                                onChange={e => { setPassword(e.target.value); setError(''); }}
                            />
                            <div style={{ marginTop: '8px', textAlign: 'right' }}>
                                <button
                                    type="button"
                                    style={{ background: 'none', border: 'none', fontSize: '0.8125rem', color: 'var(--accent-light)', cursor: 'pointer', fontFamily: 'Inter, sans-serif', fontWeight: 500 }}
                                >
                                    Forgot password?
                                </button>
                            </div>
                        </div>

                        {error && (
                            <motion.div
                                initial={{ opacity: 0, y: -4 }}
                                animate={{ opacity: 1, y: 0 }}
                                style={{
                                    padding: '10px 14px',
                                    borderRadius: '9px',
                                    background: 'rgba(244,63,94,0.06)',
                                    border: '1.5px solid rgba(244,63,94,0.2)',
                                    fontSize: '0.8125rem',
                                    color: 'var(--error)',
                                    display: 'flex',
                                    gap: '8px',
                                    alignItems: 'center',
                                }}
                            >
                                <svg width="14" height="14" viewBox="0 0 24 24" fill="currentColor">
                                    <path d="M12 2C6.477 2 2 6.477 2 12s4.477 10 10 10 10-4.477 10-10S17.523 2 12 2zm1 15h-2v-2h2v2zm0-4h-2V7h2v6z" />
                                </svg>
                                {error}
                            </motion.div>
                        )}

                        <PulseButton type="submit" loading={loading} style={{ marginTop: '4px' }}>
                            Sign in ΓåÆ
                        </PulseButton>
                    </form>

                    {/* Divider */}
                    <div style={{ display: 'flex', alignItems: 'center', gap: '12px', margin: '20px 0' }}>
                        <div className="divider" />
                        <span style={{ fontSize: '0.75rem', color: 'var(--text-muted)', whiteSpace: 'nowrap' }}>New to Qure?</span>
                        <div className="divider" />
                    </div>

                    <Link to="/" style={{ textDecoration: 'none' }}>
                        <button
                            type="button"
                            className="btn-ghost"
                            style={{ width: '100%', justifyContent: 'center' }}
                        >
                            Create an account
                        </button>
                    </Link>
                </div>

                <p style={{ textAlign: 'center', marginTop: '20px', fontSize: '0.75rem', color: 'var(--text-muted)' }}>
                    Protected by Qure ┬╖ HIPAA-aligned
                </p>
            </motion.div>
        </div>
    );
}

import { useState } from 'react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { motion, AnimatePresence } from 'framer-motion';

import { patientSchema } from '../schemas/schemas';
import useFormStore from '../store/formStore';
import FloatingLabelInput from '../components/FloatingLabelInput';
import TagChipInput from '../components/TagChipInput';

import StepIndicator from '../components/StepIndicator';
import PulseButton from '../components/PulseButton';
import { registerPatient } from '../api/registration';

const BLOOD_GROUPS = ['A+', 'AΓêÆ', 'B+', 'BΓêÆ', 'AB+', 'ABΓêÆ', 'O+', 'OΓêÆ'];
const GENDERS = ['Male', 'Female', 'Non-binary', 'Prefer not to say'];
const RELATIONS = ['Parent', 'Sibling', 'Spouse', 'Friend', 'Child', 'Other'];
const STEPS = ['Identity', 'Medical', 'Emergency'];

const slide = {
    enter: (d) => ({ x: d > 0 ? 40 : -40, opacity: 0 }),
    center: { x: 0, opacity: 1 },
    exit: (d) => ({ x: d > 0 ? -40 : 40, opacity: 0 }),
};

const ArrowLeft = () => <svg width="14" height="14" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="2.5"><path strokeLinecap="round" strokeLinejoin="round" d="M15 19l-7-7 7-7" /></svg>;
const ShieldIcon = () => <svg width="14" height="14" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="2"><path strokeLinecap="round" strokeLinejoin="round" d="M9 12l2 2 4-4m5.618-4.016A11.955 11.955 0 0112 2.944a11.955 11.955 0 01-8.618 3.04A12.02 12.02 0 003 9c0 5.591 3.824 10.29 9 11.622 5.176-1.332 9-6.03 9-11.622 0-1.042-.133-2.052-.382-3.016z" /></svg>;

export default function PatientRegistration() {
    const [step, setStep] = useState(0);
    const [dir, setDir] = useState(1);
    const [loading, setLoading] = useState(false);
    const [success, setSuccess] = useState(false);
    const [serverError, setServerError] = useState('');
    const [allergies, setAllergies] = useState([]);
    const [medications, setMedications] = useState([]);
    const [noteLen, setNoteLen] = useState(0);

    const { patientData } = useFormStore();
    const { register, handleSubmit, formState: { errors }, setValue, watch } = useForm({
        resolver: zodResolver(patientSchema),
        defaultValues: patientData,
        mode: 'onTouched',
    });

    const goTo = (next) => { setDir(next > step ? 1 : -1); setStep(next); };

    const onSubmit = async (data) => {
        setLoading(true); setServerError('');
        try {
            await registerPatient({ ...data, allergies, medications });
            setSuccess(true);
        } catch (err) {
            setServerError(err.message);
        } finally {
            setLoading(false);
        }
    };

    return (
        <form onSubmit={handleSubmit(onSubmit)} style={{ flex: 1, display: 'flex', flexDirection: 'column', gap: '20px' }}>
            <StepIndicator steps={STEPS} currentStep={step} />

            <div style={{ flex: 1, position: 'relative', overflow: 'hidden' }}>
                <AnimatePresence custom={dir} mode="wait">
                    <motion.div
                        key={step}
                        custom={dir}
                        variants={slide}
                        initial="enter"
                        animate="center"
                        exit="exit"
                        transition={{ type: 'spring', stiffness: 380, damping: 34 }}
                        style={{ display: 'flex', flexDirection: 'column', gap: '14px' }}
                    >
                        {/* ΓöÇΓöÇ STEP 0: Identity ΓöÇΓöÇ */}
                        {step === 0 && (
                            <>
                                <div style={{ marginBottom: '4px' }}>
                                    <p className="t-heading" style={{ fontSize: '1rem', marginBottom: '2px' }}>Your account</p>
                                    <p className="t-muted">Create your patient identity on Qure.</p>
                                </div>
                                <FloatingLabelInput label="Full Name" placeholder="Your full name" error={errors.name?.message} value={watch('name') || ''} {...register('name')} />
                                <FloatingLabelInput label="Email Address" type="email" placeholder="you@example.com" error={errors.email?.message} value={watch('email') || ''} {...register('email')} />
                                <FloatingLabelInput label="Password" type="password" placeholder="Min 8 characters" hint="Choose a strong, memorable password." error={errors.password?.message} value={watch('password') || ''} {...register('password')} />
                            </>
                        )}

                        {/* ΓöÇΓöÇ STEP 1: Medical ΓöÇΓöÇ */}
                        {step === 1 && (
                            <>
                                <div style={{ marginBottom: '4px' }}>
                                    <p className="t-heading" style={{ fontSize: '1rem', marginBottom: '2px' }}>Medical Profile</p>
                                    <p className="t-muted">Help doctors prepare before your visit.</p>
                                </div>

                                {/* Blood Group */}
                                <div>
                                    <label style={{ fontSize: '0.75rem', fontWeight: 600, color: 'var(--text-secondary)', letterSpacing: '0.01em', display: 'block', marginBottom: '8px' }}>
                                        Blood Group
                                    </label>
                                    <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: '6px' }}>
                                        {BLOOD_GROUPS.map(bg => (
                                            <button
                                                key={bg}
                                                type="button"
                                                onClick={() => setValue('bloodGroup', bg)}
                                                className={`option-pill ${watch('bloodGroup') === bg ? 'active' : ''}`}
                                            >
                                                {bg}
                                            </button>
                                        ))}
                                    </div>
                                    {errors.bloodGroup && <p style={{ fontSize: '0.75rem', color: 'var(--error)', marginTop: '6px' }}>{errors.bloodGroup.message}</p>}
                                </div>

                                {/* Gender */}
                                <div>
                                    <label style={{ fontSize: '0.75rem', fontWeight: 600, color: 'var(--text-secondary)', letterSpacing: '0.01em', display: 'block', marginBottom: '8px' }}>
                                        Gender
                                    </label>
                                    <div style={{ display: 'grid', gridTemplateColumns: 'repeat(2, 1fr)', gap: '6px' }}>
                                        {GENDERS.map(g => (
                                            <button
                                                key={g}
                                                type="button"
                                                onClick={() => setValue('gender', g)}
                                                className={`option-pill ${watch('gender') === g ? 'active' : ''}`}
                                                style={{ textAlign: 'left', padding: '9px 14px' }}
                                            >
                                                {g}
                                            </button>
                                        ))}
                                    </div>
                                    {errors.gender && <p style={{ fontSize: '0.75rem', color: 'var(--error)', marginTop: '6px' }}>{errors.gender.message}</p>}
                                </div>

                                {/* Condition Notes */}
                                <div style={{ display: 'flex', flexDirection: 'column', gap: '6px' }}>
                                    <label style={{ fontSize: '0.75rem', fontWeight: 600, color: 'var(--text-secondary)', letterSpacing: '0.01em' }}>
                                        Condition Notes <span style={{ fontWeight: 400, color: 'var(--text-muted)' }}>(optional)</span>
                                    </label>
                                    <div style={{ position: 'relative' }}>
                                        <textarea
                                            {...register('conditionNotes')}
                                            maxLength={500}
                                            rows={3}
                                            onChange={e => setNoteLen(e.target.value.length)}
                                            placeholder="Pre-existing conditions, symptoms, notes for your doctor..."
                                            className="input-field"
                                            style={{ resize: 'none', height: 'auto', lineHeight: 1.6 }}
                                        />
                                        <span style={{ position: 'absolute', bottom: '10px', right: '12px', fontSize: '0.7rem', color: 'var(--text-muted)' }}>
                                            {noteLen}/500
                                        </span>
                                    </div>
                                </div>

                                <TagChipInput label="Known Allergies" value={allergies} onChange={setAllergies} placeholder="e.g. Penicillin, Dust mites..." />
                                <TagChipInput label="Current Medications" value={medications} onChange={setMedications} placeholder="e.g. Metformin, Aspirin..." />
                            </>
                        )}

                        {/* ΓöÇΓöÇ STEP 2: Emergency ΓöÇΓöÇ */}
                        {step === 2 && (
                            <>
                                <div style={{ marginBottom: '4px' }}>
                                    <p className="t-heading" style={{ fontSize: '1rem', marginBottom: '2px' }}>Emergency Contact</p>
                                    <p className="t-muted">Who should we call in case of emergency?</p>
                                </div>

                                {/* Safe-zone card */}
                                <div
                                    className="card-elevated"
                                    style={{ padding: '16px', display: 'flex', flexDirection: 'column', gap: '14px' }}
                                >
                                    <div style={{ display: 'flex', alignItems: 'center', gap: '8px', paddingBottom: '10px', borderBottom: '1px solid var(--border)' }}>
                                        <span style={{ color: 'var(--accent-light)' }}><ShieldIcon /></span>
                                        <span style={{ fontSize: '0.75rem', fontWeight: 700, color: 'var(--text-secondary)', letterSpacing: '0.08em', textTransform: 'uppercase' }}>
                                            Emergency Contact
                                        </span>
                                    </div>

                                    <FloatingLabelInput label="Contact Name" placeholder="Full name" error={errors.emergencyName?.message} value={watch('emergencyName') || ''} {...register('emergencyName')} />

                                    <div>
                                        <label style={{ fontSize: '0.75rem', fontWeight: 600, color: 'var(--text-secondary)', letterSpacing: '0.01em', display: 'block', marginBottom: '8px' }}>
                                            Relation
                                        </label>
                                        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: '6px' }}>
                                            {RELATIONS.map(r => (
                                                <button
                                                    key={r}
                                                    type="button"
                                                    onClick={() => setValue('emergencyRelation', r)}
                                                    className={`option-pill ${watch('emergencyRelation') === r ? 'active' : ''}`}
                                                >
                                                    {r}
                                                </button>
                                            ))}
                                        </div>
                                        {errors.emergencyRelation && <p style={{ fontSize: '0.75rem', color: 'var(--error)', marginTop: '6px' }}>{errors.emergencyRelation.message}</p>}
                                    </div>

                                    <FloatingLabelInput label="Emergency Phone" type="tel" placeholder="10-digit mobile number" error={errors.emergencyPhone?.message} value={watch('emergencyPhone') || ''} {...register('emergencyPhone')} />
                                </div>

                                {serverError && (
                                    <motion.div
                                        initial={{ opacity: 0 }} animate={{ opacity: 1 }}
                                        style={{ padding: '10px 14px', borderRadius: '9px', background: 'rgba(244,63,94,0.08)', border: '1px solid rgba(244,63,94,0.2)', fontSize: '0.8125rem', color: 'var(--error)' }}
                                    >
                                        {serverError}
                                    </motion.div>
                                )}
                            </>
                        )}
                    </motion.div>
                </AnimatePresence>
            </div>

            {/* Nav buttons */}
            <div style={{ display: 'flex', gap: '10px', marginTop: 'auto' }}>
                {step > 0 && (
                    <button type="button" onClick={() => goTo(step - 1)} className="btn-ghost" style={{ flexShrink: 0 }}>
                        <ArrowLeft /> Back
                    </button>
                )}
                {step < 2 ? (
                    <PulseButton type="button" onClick={() => goTo(step + 1)}>Continue ΓåÆ</PulseButton>
                ) : (
                    <PulseButton type="submit" loading={loading} success={success} error={!!serverError}>
                        Create Account
                    </PulseButton>
                )}
            </div>
        </form>
    );
}

